import{_ as o,c as t,o as n,ai as r}from"./chunks/framework.yXUJ_dBa.js";const d=JSON.parse('{"title":"Open Source Summit Europe","description":"","frontmatter":{"title":"Open Source Summit Europe","date":"2025-08-25","bannerSmall":"https://events.linuxfoundation.org/wp-content/uploads/2025/01/OSS-EU-25-Social-Snackable.jpg","banner":"assets/events/20250825_linux_foundation_open_source_summit_banner.jpg","bannerMobile":"assets/events/20250825_linux_foundation_open_source_summit_mobile_banner.jpg","backgroundhex":"#137883","tags":["neonephos","digital sovereignty"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"EventEntryThemeComponent"},"headers":[],"relativePath":"events/2025_08_25_Linux_Foundation_Open_Source_Summit_Europe.md","filePath":"events/2025_08_25_Linux_Foundation_Open_Source_Summit_Europe.md"}'),a={name:"events/2025_08_25_Linux_Foundation_Open_Source_Summit_Europe.md"};function s(i,e,u,p,l,c){return n(),t("div",null,e[0]||(e[0]=[r('<h1 id="neonephos-at-the-open-source-summit-in-amsterdam" tabindex="-1">NeoNephos at the Open Source Summit in Amsterdam <a class="header-anchor" href="#neonephos-at-the-open-source-summit-in-amsterdam" aria-label="Permalink to &quot;NeoNephos at the Open Source Summit in Amsterdam&quot;">​</a></h1><p>Engage with and learn about NeoNephos by participating in our sessions at the upcoming <a href="https://events.linuxfoundation.org/open-source-summit-europe/" target="_blank" rel="noreferrer">Open Source Summit in Amsterdam</a>:</p><hr><p><strong>Headline</strong>: <a href="https://osseu2025.sched.com/event/25Vow/building-europes-cloud-future-neonephos-platform-mesh-mirza-kopic-sap-se-marvin-beckers-kubermatic?iframe=no&amp;w=100%25&amp;sidebar=yes&amp;bg=no" target="_blank" rel="noreferrer">Building Europe&#39;s Cloud Future: NeoNephos&#39; Platform Mesh</a></p><p><strong>Abstract</strong>: <em>The open source Platform Mesh project, is part of an open reference architecture for building a multi-provider cloud-edge continuum that should span the European continent. Some of the central questions the project wants to answer are: How can the different service offerings across a wide array of providers be unified? How can they communicate in a common language? We discuss how a combination of Cloud Native building blocks (kcp and kube-bind, among others) is used to create the foundation for the next generation of cloud platforms. We demonstrate a prototype which meshes together Kubernetes-like APIs that allows us to consume services across multiple control plane instances, instantiating what we call the “Platform Mesh”. Platform Mesh is a project in the newly founded NeoNephos Foundation, part of Linux Foundation Europe. This talk is for operators of cloud service providers and internal developer platforms (IDPs), giving them an outlook at a technology that unifies both worlds and creates a standard to consume services from (nearly) everywhere.</em></p><p><strong>Speakers</strong>: Mirza Kopic, SAP SE &amp; Marvin Beckers, Kubermatic</p><p>🗓 <strong>Date</strong>: August 25th, 2025 at 16:30 CEST.</p><hr><p><strong>Headline</strong>: <em><a href="https://events.linuxfoundation.org/open-source-summit-europe/program/schedule/" target="_blank" rel="noreferrer">NeoNephos: Building an Open Source Foundation for Europe&#39;s Digital Future</a></em></p><p><strong>Abstract</strong>: <em>In this panel discussion, founding members and leaders of the NeoNephos Foundation will share how their organizations drive open innovation through collaborative, vendor-neutral open source development. As a newly formed initiative announced at KubeCon London 2025, NeoNephos (neonephos.org) aims to support the creation of a resilient, interoperable cloud-edge continuum for Europe and beyond. Panelists will share the story behind the launch of NeoNephos, what inspired its creation, and how it brings together industry, public sector, and open source communities to solve shared challenges. They will reflect on what it means to build a foundation from the ground up, the values driving the initiative, and how NeoNephos plans to support collaboration at the intersection of cloud, edge, and European digital sovereignty. The discussion will also highlight key projects hosted by the foundation—such as Project Gardener—and explore how panelists’ organizations contribute to and leverage these solutions to drive innovation within their ecosystems.</em></p><p><strong>Speakers</strong>: Ihor Dvoretskyi, Cloud Native Computing Foundation with Additional Panelists to be Announced</p><p>🗓 <strong>Date</strong>: August 27th, 2025 at 14:10 CEST.</p><hr><p><strong>Headline</strong>: <em><a href="https://events.linuxfoundation.org/open-source-summit-europe/program/schedule/" target="_blank" rel="noreferrer">NeoNephos&#39; OpenMFP and Platform Mesh: Building Composable Enterprise Architectures</a></em></p><p><strong>Abstract</strong>: <em>OpenMFP addresses the critical challenge of fragmented user experiences in enterprise environments by establishing a unified architectural framework for micro frontend composition. The platform creates seamless digital UX by standardizing how distributed UI components integrate while preserving team autonomy and eliminating redundancies of core functionalities. Platform Mesh establishes interoperability between multiple providers by building upon the Kubernetes API and resource model. Developers and admins can discover, access, and order services from various sources through their beloved kubectl. The architectural implementation leverages a GraphQL layer that orchestrates resources through the Kubernetes Resource Model (KRM), secured by a fine grained authorization approach (ReBAC) with OpenFGA. These complementary technologies power diverse applications: Internal Developer Platforms, enterprise marketplaces and self-service portals. We&#39;ll demonstrate how NeoNephos projects reduce cognitive load, accelerate development, and support European cloud sovereignty. The talk shows how open source solutions are reshaping enterprise platform patterns through composable architecture.</em></p><p><strong>Speakers</strong>: Bastian Echterhölter &amp; Mirza Kopic, SAP SE</p><p>🗓 <strong>Date</strong>: August 27th, 2025 at 15:05 CEST.</p><p>👉 Don&#39;t miss out by securing your ticket <a href="https://events.linuxfoundation.org/lf-europe-roadshow-finance/attend/about/" target="_blank" rel="noreferrer">here</a>!</p>',18)]))}const m=o(a,[["render",s]]);export{d as __pageData,m as default};
